#include<bits/stdc++.h>
using namespace std;
int sum[500010];
int lowbit(int x)
{
    return x&-x;
}
int n,m;
void add(int x,int v)
{
    for(int i=x;i<=n;i+=lowbit(i))
    {
        sum[i]+=v;
    }
}
int query(int x)
{
    int ans=0;
    for(int i=x;i>=1;i-=lowbit(i))
    {
        ans+=sum[i];
    }
    return ans;
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        int x;
        scanf("%d",&x);
        add(i,x);
    }
    while(m--)
    {
        int op,x,y;
        scanf("%d%d%d",&op,&x,&y);
        if(op==1)
        {
            add(x,y);
        }
        else
        {
            printf("%d\n",query(y)-query(x-1));
        }
    }
    return 0;
}
